import { defineTool as defineTool2 } from "npm:@lovable.dev/mcp-js@0.20.0";
import { z as z2 } from "npm:zod@^4.4.3";
var get_product_default = defineTool2({
  name: "get_product",
  title: "Detalhes do produto",
  description: "Retorna os detalhes completos de um produto da Pientro Casa a partir do seu slug (ex.: 'vaso-alto-sol-da-manha').",
  inputSchema: {
    slug: z2.string().min(1).describe("Slug do produto.")
  },
  annotations: {
    readOnlyHint: true,
    idempotentHint: true,
    openWorldHint: false
  },
  handler: ({ slug }) => {
    const p = getMcpProductBySlug(slug);
    if (!p) {
      return {
        content: [{ type: "text", text: `Produto n\xE3o encontrado: ${slug}` }],
        isError: true
      };
    }
    return {
      content: [
        {
          type: "text",
          text: `${p.name} \u2014 ${p.tagline}. Pre\xE7o: R$ ${p.price.toFixed(2)}.`
        }
      ],
      structuredContent: {
        product: {
          slug: p.slug,
          name: p.name,
          shortName: p.shortName,
          category: p.category,
          collection: p.collection,
          price: p.price,
          compareAt: p.compareAt ?? null,
          tagline: p.tagline,
          description: p.description,
          highlights: p.highlights,
          variants: p.variants ?? []
        }
      }
    };
  }
});

